parsed.css:
:root { color-scheme: light; }
* { box-sizing: border-box; }
body { margin: 0; background: #f5f7f8; color: #1f2933; font-family: ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, Segoe UI, sans-serif; }
.intake-review { min-height: 900px; padding: 24px; display: grid; grid-template-columns: 300px minmax(0, 1fr) 360px; gap: 18px; }
.surface-header { grid-column: 1 / -1; display: flex; align-items: flex-end; justify-content: space-between; gap: 24px; border-bottom: 1px solid #d9e0e5; padding-bottom: 16px; }
h1, h2, h3, p { margin: 0; }
h1 { font-size: 26px; line-height: 1.15; letter-spacing: 0; }
h2 { font-size: 16px; line-height: 1.25; letter-spacing: 0; }
h3 { font-size: 14px; line-height: 1.25; color: #52606d; letter-spacing: 0; }
.header-note { max-width: 560px; color: #52606d; font-size: 14px; line-height: 1.45; }
.panel { background: #ffffff; border: 1px solid #d9e0e5; border-radius: 8px; min-width: 0; }
.panel-header { padding: 16px 16px 12px; border-bottom: 1px solid #edf1f4; display: flex; align-items: center; justify-content: space-between; gap: 12px; }
.panel-body { padding: 16px; }
.queue-list { display: grid; gap: 10px; padding: 12px; }
.queue-row { width: 100%; border: 1px solid #d9e0e5; border-radius: 8px; background: #ffffff; padding: 12px; text-align: left; display: grid; gap: 6px; color: inherit; font: inherit; cursor: default; }
.queue-row.is-active { border-color: #2f7d7b; background: #eef8f7; box-shadow: inset 3px 0 0 #2f7d7b; }
.queue-top { display: flex; justify-content: space-between; gap: 12px; align-items: center; }
.packet-id { font-weight: 700; font-size: 13px; color: #1f2933; }
.packet-name { font-weight: 650; font-size: 15px; }
.packet-time { font-size: 13px; color: #52606d; white-space: nowrap; }
.status { display: inline-flex; align-items: center; width: fit-content; min-height: 24px; padding: 3px 8px; border-radius: 999px; font-size: 12px; font-weight: 700; }
.status.missing { background: #fff2d6; color: #7a4c00; }
.status.verify { background: #e9f0ff; color: #244f9e; }
.status.ready { background: #e6f4ea; color: #25613b; }
.main-stack { display: grid; gap: 18px; min-width: 0; }
.selected-grid { display: grid; grid-template-columns: repeat(3, minmax(0, 1fr)); gap: 12px; }
.data-tile { border: 1px solid #edf1f4; border-radius: 8px; padding: 12px; background: #fafbfc; min-height: 74px; }
.label { display: block; color: #6b7785; font-size: 12px; line-height: 1.25; margin-bottom: 6px; }
.value { display: block; font-size: 15px; font-weight: 700; line-height: 1.3; overflow-wrap: anywhere; }
.checklist { display: grid; gap: 12px; }
.check-item { display: grid; grid-template-columns: 28px minmax(0, 1fr) auto; gap: 10px; align-items: start; padding: 12px; border: 1px solid #edf1f4; border-radius: 8px; background: #ffffff; }
.check-icon { width: 24px; height: 24px; border-radius: 50%; display: inline-flex; align-items: center; justify-content: center; font-size: 14px; font-weight: 800; }
.check-icon.ok { background: #e6f4ea; color: #25613b; }
.check-icon.warn { background: #fff2d6; color: #7a4c00; }
.check-title { font-weight: 700; font-size: 14px; line-height: 1.3; }
.check-detail { color: #52606d; font-size: 13px; line-height: 1.4; margin-top: 3px; }
.side-stack { display: grid; gap: 18px; align-content: start; }
.policy-box { background: #fbfaf6; border: 1px solid #e4d8b4; border-radius: 8px; padding: 14px; display: grid; gap: 10px; color: #3d3422; font-size: 13px; line-height: 1.45; }
.decision-options { display: grid; gap: 10px; }
.decision-option { border: 1px solid #c9d3db; border-radius: 8px; background: #ffffff; padding: 12px; text-align: left; font: inherit; color: #1f2933; display: grid; gap: 4px; }
.decision-option strong { font-size: 14px; }
.decision-option span { color: #52606d; font-size: 13px; line-height: 1.35; }
.decision-option.primary { border-color: #2f7d7b; background: #eef8f7; box-shadow: inset 3px 0 0 #2f7d7b; }
.decision-option.muted { color: #7b8794; background: #f8fafb; }
.handoff-summary { display: grid; gap: 12px; }
.reason { border-left: 3px solid #c97a1a; padding-left: 12px; color: #3d3422; font-size: 14px; line-height: 1.45; }
.send-button { width: 100%; border: 0; border-radius: 8px; background: #2f7d7b; color: #ffffff; min-height: 44px; padding: 10px 14px; font: inherit; font-weight: 800; }
.secondary-note { color: #52606d; font-size: 12px; line-height: 1.4; }
@media (max-width: 1100px) { .intake-review { grid-template-columns: 280px minmax(0, 1fr); } .side-stack { grid-column: 1 / -1; grid-template-columns: repeat(2, minmax(0, 1fr)); } }
@media (max-width: 760px) { .intake-review { padding: 14px; grid-template-columns: 1fr; } .surface-header, .side-stack, .selected-grid { grid-template-columns: 1fr; display: grid; } }

