  <header class='surface-header'>
    <div>
      <h1>Administrative intake readiness review</h1>
      <p class='header-note'>Review the intake packet, confirm required administrative items, and send the next action for scheduling support.</p>
    </div>
    <span class='status missing'>Consent missing</span>
  </header>

  <section class='panel' aria-labelledby='queue-title'>
    <div class='panel-header'>
      <h2 id='queue-title'>Intake queue</h2>
      <span class='label'>3 requests</span>
    </div>
    <div class='queue-list'>
      <button type='button' class='queue-row is-active' aria-label='Select packet I-4471'>
        <span class='queue-top'><span class='packet-id'>I-4471</span><span class='packet-time'>10:30 AM</span></span>
        <span class='packet-name'>Avery Morgan</span>
        <span class='status missing'>Consent missing</span>
      </button>
      <button type='button' class='queue-row' aria-label='Select packet I-4472'>
        <span class='queue-top'><span class='packet-id'>I-4472</span><span class='packet-time'>1:00 PM</span></span>
        <span class='packet-name'>Sam Rivera</span>
        <span class='status verify'>Verify insurance</span>
      </button>
      <button type='button' class='queue-row' aria-label='Select packet I-4473'>
        <span class='queue-top'><span class='packet-id'>I-4473</span><span class='packet-time'>3:15 PM</span></span>
        <span class='packet-name'>Jules Kim</span>
        <span class='status ready'>Ready to schedule</span>
      </button>
    </div>
  </section>

  <div class='main-stack'>
    <section class='panel' aria-labelledby='selected-title'>
      <div class='panel-header'>
        <h2 id='selected-title'>Selected packet</h2>
        <span class='packet-id'>I-4471</span>
      </div>
      <div class='panel-body selected-grid'>
        <div class='data-tile'><span class='label'>Patient</span><span class='value'>Avery Morgan</span></div>
        <div class='data-tile'><span class='label'>Request</span><span class='value'>New patient consult</span></div>
        <div class='data-tile'><span class='label'>Appointment slot</span><span class='value'>10:30 AM</span></div>
      </div>
    </section>

    <section class='panel' aria-labelledby='checklist-title'>
      <div class='panel-header'>
        <h2 id='checklist-title'>Readiness checklist</h2>
        <span class='status missing'>Scheduling blocked</span>
      </div>
      <div class='panel-body checklist'>
        <div class='check-item'>
          <span class='check-icon ok'>✓</span>
          <div><p class='check-title'>Referral</p><p class='check-detail'>Referral document is uploaded and available for the appointment request.</p></div>
          <span class='status ready'>Complete</span>
        </div>
        <div class='check-item'>
          <span class='check-icon ok'>✓</span>
          <div><p class='check-title'>Insurance information</p><p class='check-detail'>Insurance card image is present. No insurance uncertainty is noted for escalation.</p></div>
          <span class='status ready'>Present</span>
        </div>
        <div class='check-item'>
          <span class='check-icon warn'>!</span>
          <div><p class='check-title'>Signed consent</p><p class='check-detail'>Signed consent form is missing and is required before this request can be scheduled.</p></div>
          <span class='status missing'>Missing</span>
        </div>
      </div>
    </section>
  </div>

  <div class='side-stack'>
    <section class='panel' aria-labelledby='policy-title'>
      <div class='panel-header'><h2 id='policy-title'>Administrative policy</h2></div>
      <div class='panel-body'>
        <div class='policy-box'>
          <p>Schedule only when required administrative forms are complete.</p>
          <p>Insurance uncertainty goes to verification staff.</p>
          <p>This review is administrative only and does not include diagnosis, triage, or treatment recommendations.</p>
        </div>
      </div>
    </section>

    <section class='panel' aria-labelledby='decision-title'>
      <div class='panel-header'><h2 id='decision-title'>Decision path</h2></div>
      <div class='panel-body decision-options'>
        <button type='button' class='decision-option muted' disabled><strong>Ready to schedule</strong><span>Available after required administrative forms are complete.</span></button>
        <button type='button' class='decision-option primary' aria-pressed='true'><strong>Return for consent</strong><span>Signed consent is missing before the appointment can be scheduled.</span></button>
        <button type='button' class='decision-option'><strong>Escalate insurance verification</strong><span>Use when insurance information is uncertain or needs verification staff review.</span></button>
      </div>
    </section>

    <section class='panel' aria-labelledby='handoff-title'>
      <div class='panel-header'><h2 id='handoff-title'>Intake handoff</h2><span class='status missing'>Next action</span></div>
      <div class='panel-body handoff-summary'>
        <div><span class='label'>Administrative handoff</span><span class='value'>Return the packet for consent</span></div>
        <p class='reason'>Signed consent is missing before the appointment can be scheduled. Keep the request in administrative review until the form is returned.</p>
        <button type='button' class='send-button'>Send handoff</button>
        <p class='secondary-note'>Owner: Intake coordinator</p>
      </div>
    </section>
  </div>
</main>"}
